import { describe, it, expect } from "vitest";
import { runScenario } from "./claim-office.js";

describe("MHPCO Claim Office", () => {
  it.todo("returns no results for an empty steps array");
  it.todo("quotes a single sword for a new customer (base + first-insurance surcharge + processing fee)");
  it.todo("quotes each main item type with its own base premium");
  it.todo("applies the 50% cursed surcharge");
  it.todo("applies the 30% high-enchantment surcharge (level >= 5)");
  it.todo("applies the 20% loyalty discount for customers with >= 2 years");
  it.todo("applies the 15% repeat-contract discount on quotes after the first");
  it.todo("prices a single component (rune or moonstone) at 25 G base premium");
  it.todo("prices a bundle of 3 alike components at 60 G base premium");
  it.todo("rounds the final premium up (in MHPCO's favor)");
  it.todo("returns a claim payout of 0 when damage is below the 100 G deductible");
  it.todo("reimburses dragon-material damage in full, minus the deductible");
  it.todo("reimburses high-enchantment (level >= 8) damage at 50%, minus the deductible");
  it.todo("returns 0 payout when neither dragon material nor high enchantment applies");
});

