  it.todo("applies the 50% cursed surcharge");
  it.todo("applies the 30% high-enchantment surcharge (level >= 5)");
  it.todo("applies the 20% loyalty discount for customers with >= 2 years");
  it.todo("applies the 15% repeat-contract discount on quotes after the first");
